solution.code:
from collections import Counter

def get_signature(word):
    freq = Counter(word.lower())
    return "".join(f"{c}{f}" for c, f in sorted(freq.items()))

if __name__ == "__main__":
    print(f"'Listen': {get_signature('Listen')}")
    print(f"'Silent': {get_signature('Silent')}")
